import { describe, it, expect, beforeAll } from 'vitest';
import { env } from 'cloudflare:test';

// @ts-ignore - env is available in the test environment
const BASE_URL = (env as any).KEYPOOL_UNIVERSAL_BASE_URL;
// @ts-ignore
const BEARER_TOKEN = (env as any).KEYPOOL_UNIVERSAL_BEARER;

const shouldSkipTests = !BASE_URL || !BEARER_TOKEN;

function authedFetch(path: string, init?: RequestInit) {
  return fetch(`${BASE_URL}${path}`, {
    ...init,
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${BEARER_TOKEN}`,
      ...init?.headers,
    },
  });
}

async function parseSSE(response: Response) {
  const text = await response.text();
  const lines = text.split('\n').filter(line => line.startsWith('data: '));
  return lines.map(line => {
    try {
      return JSON.parse(line.slice(6));
    } catch {
      return {};
    }
  });
}

// Returns true if `text` is a non-trivial, non-empty answer rather than an
// empty/whitespace-only or degenerate model response.
function isCoherentText(text: unknown, minLength = 5): text is string {
  return typeof text === 'string' && text.trim().length >= minLength;
}

function containsAny(text: string, keywords: RegExp): boolean {
  return keywords.test(text);
}

beforeAll(() => {
  if (shouldSkipTests) {
    console.warn('KEYPOOL_UNIVERSAL_BASE_URL or KEYPOOL_UNIVERSAL_BEARER not set, skipping e2e tests');
  }
});

describe('Keypool Universal E2E Tests', () => {
  describe('GET /v1/keypool/universal/models', () => {
    it.skipIf(shouldSkipTests)('should return a list of models', async () => {
      const res = await authedFetch('/v1/keypool/universal/models');
      expect(res.status).toBe(200);
      const body = await res.json() as { data: Array<{ id: string; owned_by: string }> };
      expect(Array.isArray(body.data)).toBe(true);
      expect(body.data.length).toBeGreaterThan(0);
    });
  });

  describe('POST /v1/keypool/universal/chat/completions', () => {
    describe('Models without tools', () => {
      it.skipIf(shouldSkipTests)('should return a non-streaming completion for groq/meta-llama/llama-4-scout-17b-16e-instruct', async () => {
        const res = await authedFetch('/v1/keypool/universal/chat/completions', {
          method: 'POST',
          body: JSON.stringify({
            model: 'groq/meta-llama/llama-4-scout-17b-16e-instruct',
            messages: [{ role: 'user', content: 'Dis-moi bonjour.' }],
            max_tokens: 50,
          }),
        });
        expect(res.status).toBe(200);
        const body = await res.json() as {
          object: string;
          model: string;
          choices: Array<{ message: { role: string; content: string }; finish_reason: string }>;
        };
        expect(body.object).toBe('chat.completion');
        expect(body.model).toBe('groq/meta-llama/llama-4-scout-17b-16e-instruct');
        expect(body.choices[0].message.role).toBe('assistant');
        expect(body.choices[0].message.content).toBeTruthy();
        expect(['stop', 'length'].includes(body.choices[0].finish_reason)).toBe(true);
      });
    });

    describe('Models with tools', () => {
      const tools = [
        {
          type: 'function',
          function: {
            name: 'date',
            description: 'Get the current date',
            parameters: { type: 'object', properties: {} },
          },
        },
        {
          type: 'function',
          function: {
            name: 'get_wiki_ai',
            description: 'Get Wikipedia content for Artificial Intelligence',
            parameters: { type: 'object', properties: {} },
          },
        },
      ];

      const modelsWithTools = [
        'cohere/command-a-plus-05-2026',
        'cohere/north-mini-code-1-0',
        'poolside/poolside/laguna-m.1',
        'poolside/poolside/laguna-xs.2',
      ];

      modelsWithTools.forEach(model => {
        it.skipIf(shouldSkipTests)(`should handle tools for ${model}`, async () => {
          const res = await authedFetch('/v1/keypool/universal/chat/completions', {
            method: 'POST',
            body: JSON.stringify({
              model,
              messages: [{ role: 'user', content: "Quelle est la date aujourd'hui ?" }],
              tools,
              max_tokens: 50,
            }),
          });
          // Accept 200, 502, or 400 (some models may not support tools)
          expect([200, 502, 400].includes(res.status)).toBe(true);
          if (res.status === 200) {
            const body = await res.json();
            // Just verify the response structure is valid
            expect(body.choices).toBeDefined();
            expect(Array.isArray(body.choices)).toBe(true);
          }
        });
      });
    });

    describe('Models with image input', () => {
      const base64Image = 'data:image/webp;base64,';
      const modelsWithImage = [
        'cohere/command-a-plus-05-2026',
        'mistral/mistral-medium-latest',
        'gemini/gemini-3-flash-preview'
      ];

      modelsWithImage.forEach(model => {
        it.skipIf(shouldSkipTests)(`should handle image input for ${model}`, async () => {
          const res = await authedFetch('/v1/keypool/universal/chat/completions', {
            method: 'POST',
            body: JSON.stringify({
              model,
              messages: [
                {
                  role: 'user',
                  content: [
                    { type: 'text', text: 'Describe this image.' },
                    { type: 'image_url', image_url: { url: base64Image } },
                  ],
                },
              ],
              max_tokens: 50,
            }),
          });
          // Accept 200, 502, or 400 (some models may not support images)
          expect([200, 502, 400].includes(res.status)).toBe(true);
          if (res.status === 200) {
            const body = await res.json();
            // Just verify the response structure is valid
            expect(body.choices).toBeDefined();
            expect(Array.isArray(body.choices)).toBe(true);
          }
        });
      });
    });

    describe('Streaming (SSE)', () => {
      it.skipIf(shouldSkipTests)('should stream SSE for cohere/command-a-plus-05-2026', async () => {
        const res = await authedFetch('/v1/keypool/universal/chat/completions', {
          method: 'POST',
          body: JSON.stringify({
            model: 'cohere/command-a-plus-05-2026',
            messages: [{ role: 'user', content: 'Tell me a joke.' }],
            stream: true,
            max_tokens: 50,
          }),
        });
        // Accept 200 or 502
        expect([200, 502].includes(res.status)).toBe(true);
        if (res.status === 200) {
          expect(res.headers.get('content-type')).toContain('text/event-stream');
          const chunks = await parseSSE(res);
          expect(chunks.length).toBeGreaterThan(0);
          const contentChunk = chunks.find((c: any) => c.choices?.[0]?.delta?.content);
          expect(contentChunk).toBeTruthy();
        }
      });
    });

    describe('Error cases', () => {
      it.skipIf(shouldSkipTests)('should return 404 for unknown model', async () => {
        const res = await authedFetch('/v1/keypool/universal/chat/completions', {
          method: 'POST',
          body: JSON.stringify({
            model: 'unknown/model',
            messages: [{ role: 'user', content: 'Hello' }],
          }),
        });
        expect([404, 502].includes(res.status)).toBe(true);
        if (res.status === 404) {
          const body = await res.json();
          expect(body.error).toBeDefined();
        }
      });

      it.skipIf(shouldSkipTests)('should return 401 for invalid bearer token', async () => {
        const res = await fetch(`${BASE_URL}/v1/keypool/universal/models`, {
          headers: {
            Authorization: 'Bearer invalid-token',
          },
        });
        expect(res.status).toBe(401);
      });

      it.skipIf(shouldSkipTests)('should return 400 for empty messages', async () => {
        const res = await authedFetch('/v1/keypool/universal/chat/completions', {
          method: 'POST',
          body: JSON.stringify({
            model: 'groq/meta-llama/llama-4-scout-17b-16e-instruct',
            messages: [],
          }),
        });
        expect(res.status).toBe(400);
      });
    });
  });
}, 60_000);
